// Parse JSON array of ready order numbers
var readyOrders;
try {
    readyOrders = JSON.parse(msg.payload);
} catch(e) {
    readyOrders = [msg.payload];
}

// Skip empty arrays
if (!Array.isArray(readyOrders) || readyOrders.length === 0) {
    return null;
}

// Get previously announced orders from flow context
var announced = flow.get('announcedOrders') || [];

// Find only NEW orders (not yet announced)
var newOrders = readyOrders.filter(function(order) {
    return announced.indexOf(order) === -1;
});

// If no new orders, stop
if (newOrders.length === 0) {
    return null;
}

// Save all current ready orders as announced
flow.set('announcedOrders', readyOrders);

// Build announcement text
var text;
if (newOrders.length === 1) {
    text = 'Order number ' + newOrders[0] + ' is ready for pickup';
} else {
    var last = newOrders.pop();
    text = 'Orders ' + newOrders.join(', ') + ' and ' + last + ' are ready for pickup';
}

var encoded = encodeURIComponent(text);
msg.url = 'https://translate.google.com/translate_tts?ie=UTF-8&client=tw-ob&tl=en&q=' + encoded;
msg.headers = { 'User-Agent': 'Mozilla/5.0' };
msg.method = 'GET';

return msg;

const boundary = '----NodeREDFormBoundary';
const filename = 'tts_announcement.mp3';

// msg.payload contains MP3 binary from Google TTS
const audioBuffer = msg.payload;

// Construct multipart form body
const header = Buffer.from(
    `--${boundary}\r\n` +
    `Content-Disposition: form-data; name="file"; filename="${filename}"\r\n` +
    `Content-Type: audio/mpeg\r\n\r\n`
);
const footer = Buffer.from(`\r\n--${boundary}--\r\n`);

msg.payload = Buffer.concat([header, audioBuffer, footer]);
msg.headers = {
    'Content-Type': `multipart/form-data; boundary=${boundary}`
};
msg.url = 'http://10.129.174.195/axis-cgi/mediaclip.cgi?action=upload';
msg.method = 'POST';

return msg;

// Response is like "OK\nUploaded=3" or "OK\nReplaced=3"
const response = msg.payload;
const match = response.match(/(?:Uploaded|Replaced)=(\d+)/);

if (match) {
    const clipId = match[1];
    msg.url = `http://10.129.174.195/axis-cgi/mediaclip.cgi?action=play&clip=${clipId}`;
    msg.method = 'GET';
    msg.headers = {};
    msg.payload = null;
    return msg;
}

node.error('Failed to parse clip ID from: ' + response);
return null;
